import React, { useState, useRef, useEffect } from 'react';
import { useCalendar } from '../context/CalendarContext';
import '../styles/ChatInterface.css';

const ChatInterface = () => {
    const [messages, setMessages] = useState([]);
    const [inputValue, setInputValue] = useState('');
    const [pendingTask, setPendingTask] = useState(null);
    const [pendingEdit, setPendingEdit] = useState(null);
    const messagesEndRef = useRef(null);
    const { addTask, updateTask, setIsCalendarExpanded } = useCalendar();

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    };

    useEffect(() => {
        scrollToBottom();
    }, [messages]);

    const formatAIResponse = (data) => {
        if (data.error) return `Sorry, I couldn't process that. ${data.error}`;
        
        // Use the AI's dynamic message if available
        if (data.ai_message) {
            return data.ai_message;
        }
        
        // Fallback to default formatting if no AI message
        const [year, month, day] = data.startDate.split('-').map(Number);
        const date = new Date(year, month - 1, day);
        
        const formattedDate = date.toLocaleDateString('en-US', { 
            weekday: 'long', 
            year: 'numeric', 
            month: 'long', 
            day: 'numeric' 
        });

        // Log the dates for debugging
        console.log('Original startDate:', data.startDate);
        console.log('Parsed date object:', date);
        console.log('Formatted date string:', formattedDate);

        return `I've scheduled "${data.description}" for ${formattedDate}. Would you like me to: 1. Add more details to this task 2. Set up a reminder 3. Make it a recurring event`;
    };

    const generateSuggestions = (data) => {
        // Use dynamic suggestions if available
        if (data.suggestions && Array.isArray(data.suggestions)) {
            return data.suggestions;
        }

        // Fallback to default suggestions
        const suggestions = [
            "Add more details",
            "Set a reminder",
            "Make it recurring"
        ];

        if (data.recurrence) {
            suggestions.push("Change recurrence pattern");
        }

        return suggestions;
    };

    const handleSuggestionClick = (suggestion) => {
        switch (suggestion) {
            case "Add more details":
                setInputValue("Add more details to the task");
                break;
            case "Set a reminder":
                setInputValue("Set a reminder for this task");
                break;
            case "Make it recurring":
                setInputValue("Make this task recurring");
                break;
            default:
                setInputValue(suggestion);
        }
    };

    const handleTaskConfirmation = async () => {
        if (!pendingTask) return;

        try {
            // Ensure we have a start date, default to today if not provided
            const today = new Date().toISOString().split('T')[0];
            const formattedTask = {
                ...pendingTask,
                start_date: pendingTask.startDate || today,
                end_date: pendingTask.endDate || pendingTask.startDate || today,
                date: pendingTask.startDate || today,  // Add this for backend compatibility
                // Ensure all required fields are present
                title: pendingTask.title || pendingTask.description,
                description: pendingTask.description || pendingTask.title,
                time: pendingTask.time || '',
                color: pendingTask.color || '#2196F3'
            };

            console.log('Confirming task with data:', formattedTask);
            
            // Add task to calendar
            await addTask(formattedTask, false);
            
            // Add confirmation message
            setMessages(prev => [...prev, {
                type: 'assistant',
                content: `✅ Task "${formattedTask.title}" has been added to your calendar!`,
                timestamp: new Date()
            }]);

            // Expand calendar and highlight new task
            setIsCalendarExpanded(true);
            setPendingTask(null);

        } catch (error) {
            console.error('Error in task confirmation:', error);
            setMessages(prev => [...prev, {
                type: 'assistant',
                content: `Failed to confirm task: ${error.message}. Please try again.`,
                timestamp: new Date()
            }]);
        }
    };

    const handleEditRequest = async (editData) => {
        try {
            // First, get the matched task from the initial response
            const matchedTask = editData.matched_tasks?.[0];
            if (!matchedTask) {
                throw new Error('No matching task found');
            }

            // Store the task information for the edit
            const editContext = {
                task: matchedTask,
                date: editData.task_date,
                original_input: editData.original_input
            };

            // Send edit request to backend
            const response = await fetch('http://localhost:5000/api/tasks/edit', {
                method: 'POST',
                headers: { 
                    'Content-Type': 'application/json',
                    'Accept': 'application/json'
                },
                body: JSON.stringify({ 
                    query: editData.original_input,
                    task_id: matchedTask.group_id
                })
            });

            if (!response.ok) {
                throw new Error(`Server error: ${response.status}`);
            }

            const result = await response.json();
            console.log('Edit response:', result);

            if (result.error) {
                throw new Error(result.error);
            }

            // Store both the edit instructions and the task to be edited
            setPendingEdit({
                ...result,
                task_to_edit: matchedTask,
                original_input: editData.original_input
            });

            // Format the changes for display
            const changeDescriptions = result.changes.map(change => {
                const fieldMap = {
                    'dates': 'date',
                    'startDate': 'start date',
                    'endDate': 'end date'
                };
                const fieldName = fieldMap[change.field] || change.field;
                return `- ${fieldName}: ${change.value}`;
            });

            // Add AI response for edit confirmation
            const aiMessage = {
                type: 'assistant',
                content: `I'll help you edit "${matchedTask.title}". Here's what I'm going to change:\n${changeDescriptions.join('\n')}\n\nWould you like me to apply these changes? (yes/no)`,
                timestamp: new Date(),
                editDetails: result,
                confirmButton: true,
                confirmationType: 'edit'
            };

            setMessages(prev => [...prev, aiMessage]);
        } catch (error) {
            console.error('Error processing edit:', error);
            setMessages(prev => [...prev, {
                type: 'assistant',
                content: `Error: ${error.message}. Please try again or rephrase your request.`,
                timestamp: new Date()
            }]);
        }
    };

    const handleEditConfirmation = async (selectedTask) => {
        if (!pendingEdit || !pendingEdit.task_to_edit) {
            console.error('Missing edit data or selected task');
            setMessages(prev => [...prev, {
                type: 'assistant',
                content: 'Sorry, I lost track of the edit details. Please try again.',
                timestamp: new Date()
            }]);
            setPendingEdit(null);
            return;
        }

        try {
            const taskToEdit = pendingEdit.task_to_edit;
            console.log('Updating task:', taskToEdit.group_id);
            console.log('Update data:', pendingEdit);

            // Apply the changes from the edit response
            const updatedTask = {
                ...taskToEdit,
                ...pendingEdit.changes.reduce((acc, change) => {
                    if (change.field === 'dates') {
                        acc.startDate = change.value;
                        acc.endDate = change.value;
                    } else {
                        acc[change.field] = change.value;
                    }
                    return acc;
                }, {})
            };

            // Update task through CalendarContext
            await updateTask(taskToEdit.group_id, updatedTask);

            // Add success message
            setMessages(prev => [...prev, {
                type: 'assistant',
                content: `✅ Task "${taskToEdit.title}" has been updated!`,
                timestamp: new Date()
            }]);

            // Clear pending edit
            setPendingEdit(null);

            // Expand calendar to show changes
            setIsCalendarExpanded(true);

        } catch (error) {
            console.error('Error updating task:', error);
            setMessages(prev => [...prev, {
                type: 'assistant',
                content: `Failed to update task: ${error.message}. Please try again.`,
                timestamp: new Date()
            }]);
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (!inputValue.trim()) return;

        const userMessage = {
            type: 'user',
            content: inputValue,
            timestamp: new Date()
        };

        setMessages(prev => [...prev, userMessage]);
        const currentInput = inputValue.toLowerCase().trim();
        setInputValue('');

        // Handle edit confirmation
        if (pendingEdit && (currentInput === 'yes' || currentInput === 'y')) {
            // Get the selected task from pendingEdit
            const selectedTask = pendingEdit.matched_tasks?.[0];
            if (!selectedTask) {
                console.error('No task selected for edit');
                setMessages(prev => [...prev, {
                    type: 'assistant',
                    content: 'Sorry, I lost track of which task to edit. Please try again.',
                    timestamp: new Date()
                }]);
                setPendingEdit(null);
                return;
            }
            await handleEditConfirmation(selectedTask);
            return;
        } else if (pendingEdit && (currentInput === 'no' || currentInput === 'n')) {
            setPendingEdit(null);
            setMessages(prev => [...prev, {
                type: 'assistant',
                content: 'Edit cancelled. Is there anything else I can help you with?',
                timestamp: new Date()
            }]);
            return;
        }

        try {
            const response = await fetch('http://localhost:5000/api/parse-task', {
                method: 'POST',
                headers: { 
                    'Content-Type': 'application/json',
                    'Accept': 'application/json'
                },
                body: JSON.stringify({ 
                    input: inputValue
                })
            });

            if (!response.ok) {
                throw new Error(`Server error: ${response.status}`);
            }

            const data = await response.json();
            console.log('Parsed response:', data);

            // Check if this is an edit request
            if (data.is_edit_request) {
                await handleEditRequest(data);
                return;
            }

            // Store the pending task
            setPendingTask(data);

            const aiMessage = {
                type: 'assistant',
                content: formatAIResponse(data),
                timestamp: new Date(),
                taskDetails: data,
                confirmButton: true,
                confirmationType: 'add',
                suggestions: generateSuggestions(data),
                followUpQuestions: data.follow_up_questions // Add follow-up questions
            };

            setMessages(prev => [...prev, aiMessage]);
        } catch (error) {
            console.error('Error processing message:', error);
            setMessages(prev => [...prev, {
                type: 'assistant',
                content: `Error: ${error.message}. Please try again or rephrase your request.`,
                timestamp: new Date()
            }]);
        }
    };

    return (
        <div className="chat-container">
            <div className="chat-messages">
                {messages.map((message, index) => (
                    <div key={index} className={`message ${message.type}`}>
                        <div className="message-content">{message.content}</div>
                        {message.taskDetails && (
                            <div className="task-preview">
                                <div className="task-details">
                                    <div className="task-title">{message.taskDetails.description}</div>
                                    <div className="task-date">
                                        {(() => {
                                            const [year, month, day] = message.taskDetails.start_date.split('-').map(Number);
                                            const date = new Date(year, month - 1, day);
                                            return date.toLocaleDateString('en-US', {
                                                year: 'numeric',
                                                month: 'numeric',
                                                day: 'numeric'
                                            });
                                        })()}
                                    </div>
                                </div>
                                {message.confirmButton && (
                                    <button 
                                        className="confirm-button"
                                        onClick={handleTaskConfirmation}
                                    >
                                        Confirm Task
                                    </button>
                                )}
                            </div>
                        )}
                        {message.followUpQuestions && (
                            <div className="follow-up-questions">
                                {message.followUpQuestions.map((question, i) => (
                                    <div key={i} className="follow-up-question" onClick={() => setInputValue(question)}>
                                        {question}
                                    </div>
                                ))}
                            </div>
                        )}
                        {message.suggestions && (
                            <div className="message-suggestions">
                                {message.suggestions.map((suggestion, i) => (
                                    <button 
                                        key={i} 
                                        onClick={() => handleSuggestionClick(suggestion)}
                                        className="suggestion-button"
                                    >
                                        {suggestion}
                                    </button>
                                ))}
                            </div>
                        )}
                    </div>
                ))}
                <div ref={messagesEndRef} />
            </div>
            <form onSubmit={handleSubmit} className="chat-input-form">
                <input
                    type="text"
                    value={inputValue}
                    onChange={(e) => setInputValue(e.target.value)}
                    placeholder="Type your message here..."
                    className="chat-input"
                />
                <button type="submit" className="send-button">
                    <svg viewBox="0 0 24 24" className="send-icon">
                        <path d="M2.01 21L23 12 2.01 3 2 10l15 2-15 2z" />
                    </svg>
                </button>
            </form>
        </div>
    );
};

export default ChatInterface;
